/**
 * SQL Query Validator - prevents dangerous operations
 */
class QueryValidator(permissions: UserPermissions) {

  // Blocklist of dangerous SQL patterns
  private val dangerousPatterns: Seq[String] = Seq(
    "(?i)\\bDROP\\b",
    "(?i)\\bDELETE\\b",
    "(?i)\\bTRUNCATE\\b",
    "(?i)\\bINSERT\\b",
    "(?i)\\bUPDATE\\b",
    "(?i)\\bALTER\\b",
    "(?i)\\bCREATE\\b",
    "(?i)\\bGRANT\\b",
    "(?i)\\bREVOKE\\b",
    "(?i)\\bMERGE\\b",
    "(?i)\\bSET\\b\\s",
    "(?i)\\bUNCACHE\\b",
    "(?i)\\bREFRESH\\b",
    "(?i)\\bADD\\s+JAR\\b",
    "(?i)\\bADD\\s+FILE\\b",
    "(?i)\\bLOAD\\s+DATA\\b",
    "(?i)\\bEXPLAIN\\b",
    "(?i)\\bDESC(RIBE)?\\s+EXTENDED\\b",
    "(?i)\\bSHOW\\s+CREATE\\b",
    "(?i)\\bMSCK\\b",
    "(?i)\\bREPAIR\\b",
    // Prevent UDF injection and code execution
    "(?i)\\breflect\\s*\\(",
    "(?i)\\bjava_method\\s*\\(",
    "(?i)\\btransform\\s*\\(",
    "(?i)\\bstack\\s*\\(",
    // Prevent file system access
    "(?i)\\bINPUT__FILE__NAME\\b",
    // Prevent subquery-based attacks with system tables
    "(?i)\\binformation_schema\\b",
    // Prevent comment-based injection
    "/\\*",
    "--",
    ";",
    // Prevent UNION-based data exfiltration from unauthorized tables
  )

  private val dangerousRegexes = dangerousPatterns.map(_.r)

  /**
   * Validates the SQL query for safety and authorization
   */
  def validate(sql: String): Either[String, String] = {
    for {
      _ <- checkNotEmpty(sql)
      _ <- checkSingleStatement(sql)
      _ <- checkDangerousPatterns(sql)
      _ <- checkIsSelectOnly(sql)
      _ <- checkReferencedTables(sql)
      cleaned <- Right(sql.trim)
    } yield cleaned
  }

  private def checkNotEmpty(sql: String): Either[String, Unit] = {
    if (sql == null || sql.trim.isEmpty)
      Left("Query cannot be empty")
    else
      Right(())
  }

  private def checkSingleStatement(sql: String): Either[String, Unit] = {
    // Remove string literals before checking for semicolons
    val withoutStrings = sql.replaceAll("'[^']*'", "").replaceAll("\"[^\"]*\"", "")
    if (withoutStrings.contains(";"))
      Left("Multiple statements are not allowed")
    else
      Right(())
  }

  private def checkDangerousPatterns(sql: String): Either[String, Unit] = {
    val found = dangerousRegexes.find(_.findFirstIn(sql).isDefined)
    found match {
      case Some(pattern) =>
        Left(s"Query contains disallowed pattern: ${pattern.pattern.pattern()}")
      case None =>
        Right(())
    }
  }

  private def checkIsSelectOnly(sql: String): Either[String, Unit] = {
    val trimmed = sql.trim.toLowerCase
    if (trimmed.startsWith("select") || trimmed.startsWith("with") || trimmed.startsWith("(select"))
      Right(())
    else
      Left("Only SELECT queries are allowed")
  }

  /**
   * Parse the SQL to extract referenced tables and verify permissions
   */
  private def checkReferencedTables(sql: String): Either[String, Unit] = {
    Try {
      val parser = CatalystSqlParser
      val plan: LogicalPlan = parser.parsePlan(sql)
      extractTableReferences(plan)
    } match {
      case Success(tables) =>
        val unauthorized = tables.filterNot { table =>
          val fullName = if (table.contains(".")) table else s"default.$table"
          permissions.allowedTables.contains(fullName.toLowerCase) ||
            permissions.allowedTables.contains(s"*.${table.toLowerCase}")
        }
        if (unauthorized.nonEmpty)
          Left(s"Access denied to tables: ${unauthorized.mkString(", ")}")
        else
          Right(())
      case Failure(e) =>
        Left(s"Failed to parse SQL query: ${e.getMessage}")
    }
  }

  private def extractTableReferences(plan: LogicalPlan): Set[String] = {
    plan.collect {
      case UnresolvedRelation(multipartIdentifier, _, _) =>
        multipartIdentifier.mkString(".")
    }.toSet
  }
}

/**
 * Audit logger for all query executions
 */
class QueryAuditLogger(spark: SparkSession) {

  def logQuery(
    queryId: String,
    userId: String,
    sql: String,
    status: String,
    executionTimeMs: Long,
    rowCount: Long,
    errorMessage: Option[String] = None
  ): Unit = {
    import spark.implicits._
    val timestamp = Instant.now().toString
    val auditRecord = Seq((queryId, userId, sql, status, executionTimeMs, rowCount, errorMessage.getOrElse(""), timestamp))
      .toDF("query_id", "user_id", "sql_text", "status", "execution_time_ms", "row_count", "error_message", "timestamp")

    // In production, write to a dedicated audit table
    auditRecord.write
      .mode("append")
      .format("delta") // or parquet, depending on your data lake
      .saveAsTable("audit.query_log")

    println(s"[AUDIT] queryId=$queryId userId=$userId status=$status time=${executionTimeMs}ms rows=$rowCount")
  }
}

/**
 * Rate limiter to prevent abuse
 */
class RateLimiter(maxQueriesPerMinute: Int = 30) {
  private val queryTimestamps = scala.collection.concurrent.TrieMap[String, Seq[Long]]()

  def checkRateLimit(userId: String): Either[String, Unit] = {
    val now = System.currentTimeMillis()
    val oneMinuteAgo = now - 60000
    val timestamps = queryTimestamps.getOrElse(userId, Seq.empty).filter(_ > oneMinuteAgo)

    if (timestamps.size >= maxQueriesPerMinute) {
      Left(s"Rate limit exceeded: max $maxQueriesPerMinute queries per minute")
    } else {
      queryTimestamps.update(userId, timestamps :+ now)
      Right(())
    }
  }
}

