/**
 * Secure SQL Query Execution Engine
 */
class SecureQueryEngine(spark: SparkSession) {

  private val auditLogger = new QueryAuditLogger(spark)
  private val rateLimiter = new RateLimiter(maxQueriesPerMinute = 30)

  /**
   * Securely execute a user query with full validation, authorization, and auditing
   */
  def executeQuery(request: QueryRequest): Either[QueryError, QueryResult] = {
    val queryId = java.util.UUID.randomUUID().toString
    val startTime = System.currentTimeMillis()

    val result = for {
      // Step 1: Rate limiting
      _ <- rateLimiter.checkRateLimit(request.userId).left.map(msg =>
        QueryError(queryId, errorMessage = msg, errorType = "RATE_LIMIT_EXCEEDED"))

      // Step 2: Get user permissions
      permissions = PermissionService.getPermissions(request.userId)

      // Step 3: Validate and sanitize the query
      validator = new QueryValidator(permissions)
      validatedSql <- validator.validate(request.sql).left.map(msg =>
        QueryError(queryId, errorMessage = msg, errorType = "VALIDATION_ERROR"))

      // Step 4: Apply resource limits
      maxRows = Math.min(
        request.maxRows.getOrElse(permissions.maxRowsLimit),
        permissions.maxRowsLimit
      )
      limitedSql = applyRowLimit(validatedSql, maxRows)

      // Step 5: Execute with timeout and resource constraints
      result <- executeWithSafeguards(queryId, request.userId, limitedSql, request, permissions)
    } yield result

    // Audit logging regardless of success/failure
    val executionTime = System.currentTimeMillis() - startTime
    result match {
      case Right(qr) =>
        auditLogger.logQuery(queryId, request.userId, request.sql, "SUCCESS", executionTime, qr.rowCount)
      case Left(err) =>
        auditLogger.logQuery(queryId, request.userId, request.sql, "FAILED", executionTime, 0, Some(err.errorMessage))
    }

    result
  }

  /**
   * Wrap query with a row limit to prevent excessive data retrieval
   */
  private def applyRowLimit(sql: String, maxRows: Int): String = {
    // Wrap in a subquery with LIMIT to enforce max rows
    s"SELECT * FROM ($sql) __limited_query LIMIT $maxRows"
  }

  /**
   * Execute with timeout, resource group, and error handling
   */
  private def executeWithSafeguards(
    queryId: String,
    userId: String,
    sql: String,
    request: QueryRequest,
    permissions: UserPermissions
  ): Either[QueryError, QueryResult] = {

    val timeoutSeconds = Math.min(
      request.timeoutSeconds.getOrElse(permissions.maxTimeoutSeconds),
      permissions.maxTimeoutSeconds
    )

    Try {
      // Set Spark configurations for resource isolation
      spark.conf.set("spark.sql.shuffle.partitions", "50")
      // Set a scheduler pool for fair scheduling (if configured)
      spark.sparkContext.setLocalProperty("spark.scheduler.pool", s"user_queries")
      spark.sparkContext.setJobGroup(queryId, s"User query from $userId", interruptOnCancel = true)

      // Schedule a timeout cancellation
      val timeoutThread = new Thread(() => {
        Thread.sleep(timeoutSeconds * 1000L)
        spark.sparkContext.cancelJobGroup(queryId)
      })
      timeoutThread.setDaemon(true)
      timeoutThread.start()

      try {
        val startExec = System.currentTimeMillis()

        // Execute using Spark's built-in SQL views only (no raw table access)
        // The user can only query pre-registered views/tables
        val df: DataFrame = spark.sql(sql)

        val rows = df.collect()
        val columns = df.columns.toSeq
        val resultRows = rows.map(row => (0 until row.length).map(i => row.get(i)).toSeq).toSeq

        val execTime = System.currentTimeMillis() - startExec

        val warnings = scala.collection.mutable.ListBuffer[String]()
        val maxRows = request.maxRows.getOrElse(permissions.maxRowsLimit)
        if (resultRows.size >= maxRows) {
          warnings += s"Results truncated to $maxRows rows"
        }

        QueryResult(
          queryId = queryId,
          status = "SUCCESS",
          columns = columns,
          rows = resultRows,
          rowCount = resultRows.size.toLong,
          executionTimeMs = execTime,
          warnings = warnings.toSeq
        )
      } finally {
        timeoutThread.interrupt()
        spark.sparkContext.clearJobGroup()
      }
    } match {
      case Success(result) => Right(result)
      case Failure(e) if e.getMessage != null && e.getMessage.contains("cancelled") =>
        Left(QueryError(queryId, errorMessage = s"Query timed out after ${timeoutSeconds}s", errorType = "TIMEOUT"))
      case Failure(e) =>
        Left(QueryError(queryId, errorMessage = s"Query execution failed: ${e.getMessage}", errorType = "EXECUTION_ERROR"))
    }
  }
}

